### 4-3. 팔로우 수 캐시 (feed/matching에서 빈번히 참조)

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: StringRedisTemplate,  // 카운터는 StringRedisTemplate 사용
) {
    companion object {
        private const val FOLLOW_COUNT_KEY = "maum::user:follow:count:followerId:"
        private const val TTL_MINUTES = 5L
    }

    // @Cacheable 대신 RedisTemplate 직접 사용 (증감 연산 지원)
    fun getFollowerCount(userId: String): Long {
        val key = "$FOLLOW_COUNT_KEY$userId"
        val cached = redisTemplate.opsForValue().get(key)
        if (cached != null) return cached.toLong()

        val count = followRepository.countByFolloweeId(userId)
        redisTemplate.opsForValue().set(key, count.toString(), Duration.ofMinutes(TTL_MINUTES))
        return count
    }

    @Transactional
    fun follow(followerId: String, followeeId: String) {
        followRepository.save(FollowEntity(followerId = followerId, followeeId = followeeId))
        // 팔로우 시 카운터 즉시 증가 (캐시 무효화 대신 increment로 정합성 유지)
        val key = "$FOLLOW_COUNT_KEY$followeeId"
        if (redisTemplate.hasKey(key) == true) {
            redisTemplate.opsForValue().increment(key)
        }
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
        val key = "$FOLLOW_COUNT_KEY$followeeId"
        if (redisTemplate.hasKey(key) == true) {
            redisTemplate.opsForValue().decrement(key)
        }
    }
}
```

