@Service
class NotificationSettingService(
    private val settingRepository: NotificationSettingRepository,
) {
    // 알림 발송마다 조회 -> 높은 빈도의 읽기
    @Cacheable(
        cacheNames = [CacheConfig.NOTIFICATION_SETTING],
        key = "'userId:' + #userId",
