### 4-5. 통화 상태 캐시 (실시간 매칭용, 짧은 TTL)

```kotlin
@Service
class CallStatusService(
    private val redisTemplate: RedisTemplate<String, String>,
) {
    companion object {
        private const val CALL_AVAILABLE_KEY = "maum::call:available:"
        private val TTL = Duration.ofSeconds(30)  // 30초 TTL (실시간성 우선)
    }

    // 통화 가능 여부: 매칭 알고리즘에서 대량 조회
    fun isAvailable(userId: String): Boolean {
        val key = "$CALL_AVAILABLE_KEY$userId"
        return redisTemplate.opsForValue().get(key) == "true"
    }

    fun setAvailable(userId: String, available: Boolean) {
        val key = "$CALL_AVAILABLE_KEY$userId"
        redisTemplate.opsForValue().set(key, available.toString(), TTL)
    }

    // 통화 시작 시: 양측 상태 동시 업데이트
    fun startCall(callerId: String, receiverId: String) {
        setAvailable(callerId, false)
        setAvailable(receiverId, false)
        // 통화 중 상태는 TTL로 자동 만료 -> 비정상 종료 시 자동 복구
    }
}
```

